import type {
  AdapterCapabilities,
  AdapterCategory,
  AdapterSubscription,
  ConnectionStatus,
  ExchangeAdapter,
  ExchangeConfig,
  HealthMetrics,
  OHLCVCallback,
  OrderbookCallback,
  StatusCallback,
  TickerCallback,
  TradeCallback,
} from '../../types/adapter';
import type { NormalizedOHLCV, NormalizedOrderbook, NormalizedSymbol, NormalizedTrade, Timeframe } from '../../types/normalized';
import { createSubscriptionId, parseNumeric, secondsToMs } from '../../normalization/pipeline';
import type {
  BirdeyeApiResponse,
  BirdeyeHistoryPriceData,
  BirdeyeOHLCVData,
  BirdeyePriceData,
  BirdeyeTimeType,
  BirdeyeTokenListData,
  BirdeyeTokenOverviewData,
} from './birdeye-types';

const API_BASE_URL = 'https://public-api.birdeye.so';

/** Default polling interval (5 seconds). */
const DEFAULT_POLL_INTERVAL_MS = 5_000;

/** Timeframe to Birdeye time type mapping. */
const TIME_TYPE_MAP: Partial<Record<Timeframe, BirdeyeTimeType>> = {
  '1m': '1m', '3m': '3m', '5m': '5m', '15m': '15m', '30m': '30m',
  '1h': '1H', '2h': '2H', '4h': '4H', '6h': '6H', '12h': '12H',
  '1d': '1D', '1w': '1W',
};

interface ActiveSubscription {
  readonly id: string;
  readonly symbol: string;
  readonly tokenAddress: string;
  readonly type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv' | 'status';
  readonly callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback | StatusCallback;
}

/**
 * Birdeye adapter for Solana DeFi token data.
 *
 * REST polling adapter using the Birdeye public API. Requires an API key
 * passed via ExchangeConfig.apiKey (sent as X-API-KEY header). Supports
 * token price queries, historical OHLCV, and token discovery on Solana.
 */
export class BirdeyeAdapter implements ExchangeAdapter {
  readonly exchangeId = 'birdeye' as const;
  readonly displayName = 'Birdeye';
  readonly category: AdapterCategory = 'aggregator';
  readonly capabilities: AdapterCapabilities = {
    realtime: true,
    historicalDepth: '30d',
    orderbook: false,
    trades: true,
    ohlcv: true,
    fundingRates: false,
    openInterest: false,
    liquidations: false,
    defiMetrics: true,
    onChainMetrics: false,
    authenticated: true,
  };

  private apiUrl = API_BASE_URL;
  private apiKey = '';
  private readonly subscriptions = new Map<string, ActiveSubscription>();
  private readonly statusCallbacks = new Map<string, StatusCallback>();
  private pollTimer: ReturnType<typeof setInterval> | undefined;
  private connectTime = 0;
  private connectionState: ConnectionStatus = {
    state: 'disconnected',
    latencyMs: 0,
    messagesPerSecond: 0,
    lastMessageAt: 0,
    reconnectAttempt: 0,
    uptime: 0,
  };

  async connect(config: ExchangeConfig): Promise<void> {
    if (config.restUrl) {
      this.apiUrl = config.restUrl;
    }
    if (config.apiKey) {
      this.apiKey = config.apiKey;
    }
    if (!this.apiKey) {
      throw new Error('Birdeye requires an API key. Set ExchangeConfig.apiKey.');
    }

    this.connectTime = Date.now();
    this.updateState('connected');

    this.pollTimer = setInterval(() => {
      this.pollSubscriptions().catch(() => {
        // Polling errors are non-fatal
      });
    }, DEFAULT_POLL_INTERVAL_MS);
  }

  async disconnect(): Promise<void> {
    if (this.pollTimer !== undefined) {
      clearInterval(this.pollTimer);
      this.pollTimer = undefined;
    }
    this.subscriptions.clear();
    this.updateState('disconnected');
    this.statusCallbacks.clear();
  }

  getStatus(): ConnectionStatus {
    return { ...this.connectionState, uptime: this.getUptime() };
  }

  getHealthMetrics(): HealthMetrics {
    const status = this.getStatus();
    const uptimePercent = status.uptime > 0
      ? Math.min(100, (status.uptime / (status.uptime + status.reconnectAttempt * 5)) * 100)
      : 0;
    return {
      connected: status.state === 'connected',
      latencyMs: status.latencyMs,
      messagesPerSecond: status.messagesPerSecond,
      uptimePercent,
      lastMessageAt: status.lastMessageAt,
      errorRate: 0,
      circuitBreakerState: 'closed',
    };
  }

  onStatusChange(callback: StatusCallback): AdapterSubscription {
    const id = createSubscriptionId('birdeye', 'status', '_global');
    this.statusCallbacks.set(id, callback);
    return {
      id,
      symbol: '_global',
      type: 'status',
      dispose: () => { this.statusCallbacks.delete(id); },
    };
  }

  subscribeTicker(symbol: string, callback: TickerCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'ticker', callback);
  }

  subscribeOrderbook(_symbol: string, _depth: number, _callback: OrderbookCallback): AdapterSubscription {
    throw new Error('Birdeye does not support order books');
  }

  subscribeTrades(symbol: string, callback: TradeCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'trades', callback);
  }

  subscribeOHLCV(symbol: string, _timeframe: Timeframe, callback: OHLCVCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'ohlcv', callback);
  }

  async getCandles(symbol: string, timeframe: Timeframe, from: number, to: number): Promise<NormalizedOHLCV[]> {
    const tokenAddress = this.extractTokenAddress(symbol);
    const timeType = TIME_TYPE_MAP[timeframe];
    if (!timeType) {
      throw new Error(`Unsupported timeframe for Birdeye: ${timeframe}`);
    }

    const fromSec = Math.floor(from / 1000);
    const toSec = Math.floor(to / 1000);
    const url = `${this.apiUrl}/defi/ohlcv?address=${tokenAddress}&type=${timeType}&time_from=${fromSec}&time_to=${toSec}`;

    const response = await this.fetchBirdeye<BirdeyeOHLCVData>(url);

    return response.data.items.map(item => ({
      timestamp: secondsToMs(item.unixTime),
      open: item.o,
      high: item.h,
      low: item.l,
      close: item.c,
      volume: item.v,
      quoteVolume: item.v,
      tradeCount: 0,
      closed: true,
    }));
  }

  async getOrderbookSnapshot(_symbol: string, _depth: number): Promise<NormalizedOrderbook> {
    throw new Error('Birdeye does not support order books');
  }

  async getRecentTrades(_symbol: string, _limit: number): Promise<NormalizedTrade[]> {
    return [];
  }

  async getSymbols(): Promise<NormalizedSymbol[]> {
    const url = `${this.apiUrl}/defi/tokenlist?sort_by=v24hUSD&sort_type=desc&limit=100`;
    const response = await this.fetchBirdeye<BirdeyeTokenListData>(url);

    return response.data.tokens.map(token => ({
      symbol: `${token.symbol}/USDC`,
      base: token.symbol,
      quote: 'USDC',
      exchangeSymbol: token.address,
      exchangeId: 'birdeye' as const,
      type: 'dex-pool' as const,
      pricePrecision: token.decimals,
      quantityPrecision: token.decimals,
      minQuantity: 0,
      tickSize: 10 ** -token.decimals,
      active: token.liquidity > 0,
      contractAddress: token.address,
      chain: 'solana',
    }));
  }

  /**
   * Fetch the current price for a token via the `/defi/price` endpoint.
   * Returns the price data including the value and update timestamp.
   */
  async getTokenPrice(tokenAddress: string): Promise<BirdeyePriceData> {
    const url = `${this.apiUrl}/defi/price?address=${tokenAddress}`;
    const response = await this.fetchBirdeye<BirdeyePriceData>(url);
    return response.data;
  }

  /**
   * Fetch token overview metadata via the `/defi/token_overview` endpoint.
   */
  async getTokenOverview(tokenAddress: string): Promise<BirdeyeTokenOverviewData> {
    const url = `${this.apiUrl}/defi/token_overview?address=${tokenAddress}`;
    const response = await this.fetchBirdeye<BirdeyeTokenOverviewData>(url);
    return response.data;
  }

  // ---------------------------------------------------------------------------
  // Private helpers
  // ---------------------------------------------------------------------------

  private addSubscription(
    symbol: string,
    type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv',
    callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback,
  ): AdapterSubscription {
    const id = createSubscriptionId('birdeye', type, symbol);
    const tokenAddress = this.extractTokenAddress(symbol);
    const sub: ActiveSubscription = { id, symbol, tokenAddress, type, callback };
    this.subscriptions.set(id, sub);

    return {
      id,
      symbol,
      type,
      dispose: () => { this.subscriptions.delete(id); },
    };
  }

  private async pollSubscriptions(): Promise<void> {
    const tickerSubs = Array.from(this.subscriptions.values()).filter(s => s.type === 'ticker');
    for (const sub of tickerSubs) {
      const priceData = await this.getTokenPrice(sub.tokenAddress);
      let overview: BirdeyeTokenOverviewData | null = null;
      try {
        overview = await this.getTokenOverview(sub.tokenAddress);
      } catch {
        // Overview is supplementary; price alone is sufficient
      }

      const price = priceData.value;
      const priceChangePct = overview ? parseNumeric(overview.priceChange24hPercent) : 0;
      const volume24h = overview ? parseNumeric(overview.v24hUSD) : 0;

      const tick = {
        symbol: sub.symbol,
        lastPrice: price,
        priceChange: price * (priceChangePct / 100),
        priceChangePercent: priceChangePct,
        high24h: price,
        low24h: price,
        volume24h,
        quoteVolume24h: volume24h,
        timestamp: secondsToMs(priceData.updateUnixTime),
        bestBid: price,
        bestBidQty: 0,
        bestAsk: price,
        bestAskQty: 0,
      };

      (sub.callback as TickerCallback)(tick);
    }
  }

  private async fetchBirdeye<T>(url: string): Promise<BirdeyeApiResponse<T>> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      'X-API-KEY': this.apiKey,
    };

    const start = Date.now();
    const response = await fetch(url, { headers });
    const latency = Date.now() - start;

    this.connectionState = {
      ...this.connectionState,
      latencyMs: latency,
      lastMessageAt: Date.now(),
    };

    if (!response.ok) {
      throw new Error(`Birdeye API error: ${response.status} ${response.statusText}`);
    }

    const body = (await response.json()) as BirdeyeApiResponse<T>;
    if (!body.success) {
      throw new Error('Birdeye API returned unsuccessful response');
    }

    return body;
  }

  private extractTokenAddress(symbol: string): string {
    // If the symbol looks like a Solana address (base58, 32-44 chars), use directly
    if (/^[1-9A-HJ-NP-Za-km-z]{32,44}$/.test(symbol)) return symbol;
    // Otherwise, this is a normalized symbol -- address must be resolved via getSymbols()
    return symbol;
  }

  private updateState(state: ConnectionStatus['state'], errorMessage?: string): void {
    this.connectionState = {
      state,
      latencyMs: this.connectionState.latencyMs,
      messagesPerSecond: this.connectionState.messagesPerSecond,
      lastMessageAt: this.connectionState.lastMessageAt,
      errorMessage,
      reconnectAttempt: 0,
      uptime: this.getUptime(),
    };
    for (const callback of this.statusCallbacks.values()) {
      callback(this.connectionState);
    }
  }

  private getUptime(): number {
    if (this.connectTime === 0) return 0;
    return (Date.now() - this.connectTime) / 1000;
  }
}
